#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture( sampler_fw_main, vUv ).xyz;

    vec2 stretch = vec2(roam_cos.x, roam_sin.x)*1;
    vec2 move = vec2(roam_sin.x*1.2, roam_cos.x*1.2);
    float tex = texture(sampler_noise_hq, vUv * stretch-move);

    ret = mix(ret, 8*tex, 0.015);

    ret *= vec3(.918+.05*q2,.912+.05*q3,.905+.05*q1);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvm=0;

uvm.x=vUv.x-.07*texture(sampler_noise_hq, vUv.x*.8).x;
uvm.y=vUv.y-.07*texture(sampler_noise_hq, vUv.y*.8).x;

vec2 uvo = vUv;
//*** Flexis Moebius transformation code

vUv = (vUv-0.5)*uAspect.xy*2;
factorA = vUv;
factorB = vec2(q21,q22);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,   // the products real part
                  factorA.x*factorB.y + factorA.y*factorB.x);  // the products imaginary part

numerator = product + vec2(q23,q24);

factorA = vUv;
factorB = vec2(q25,q26);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,   // the products real part
                  factorA.x*factorB.y + factorA.y*factorB.x);  // the products imaginary part


denominator = product + vec2(q27,q28);

fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,   // the fractions real part
                   numerator.y*denominator.x - numerator.x*denominator.y)/  // the fractions imaginary part
                   (denominator.x*denominator.x + denominator.y*denominator.y);

vUv = fraction*0.5;

// ***


// *** Flexis logarithmic spiral code

float t = .33*uTime; // set velocity here
vec2 c = (vUv-0.5)*uAspect.wz;
float1 ang_hq = atan(c.x,c.y);
//q11 = 1/asin(1); from the init section
vec2 spiral = vec2(ang_hq*q11*2+t,uAspect.w*log(length(c))+ang_hq*q11-t);
spiral = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*0.95; // mirror
vUv = spiral.yx;

// ***

vec3 blur = GetBlur1(uvm);
vec3 sharp = texture(sampler_main, uvm);
vec3 fix = GetPixel(fract(uvm));

float mod = (.8*fix+cos(vRadius*2-roam_sin*2-.5*uTime));

vec3 fret = (10*fix-blur*vRadius)*mod;
vec3 inv = 1-fret;

float melt = dot(fret, inv);

ret=texture(sampler_main, vec2(vUv.x, vUv.y*.75))*inv+.55*fret;
ret=mix(ret, inv, 2*clamp01(melt));

  fragColor = ret;
}
